        if (i >= MAX_ITERATIONS) { break; }
        let mag2 = complex_f64_mag_sq(z);
        if (f64_to_f32(mag2) > ESCAPE_RADIUS_SQUARED) { break; }

        let z2 = complex_f64_mul(z, z);
        z = complex_f64_add(z2, c);
